"""คลังข้อสอบเพิ่มเติมสำหรับนำเข้า SQLite ครั้งแรก"""

EXTRA_QUESTIONS = [
    (51,"หลักประกันภัย","ภัย (Peril) ในทางประกันภัยหมายถึงอะไร?",["เหตุที่เป็นสาเหตุโดยตรงให้เกิดความเสียหาย","ทรัพย์สินที่เอาประกันภัย","จำนวนเบี้ยประกันภัย","ผู้รับประโยชน์"],"เหตุที่เป็นสาเหตุโดยตรงให้เกิดความเสียหาย","เช่น ไฟไหม้เป็นภัย ส่วนสภาพที่ทำให้ไฟไหม้ง่ายเป็นสภาวะภัย"),
    (52,"หลักประกันภัย","สภาวะภัย (Hazard) หมายถึงข้อใด?",["สภาพที่เพิ่มโอกาสหรือความรุนแรงของความเสียหาย","ค่าสินไหมที่จ่ายแล้ว","กรมธรรม์ที่สิ้นอายุ","ตัวแทนของบริษัท"],"สภาพที่เพิ่มโอกาสหรือความรุนแรงของความเสียหาย","สภาวะภัยอาจเป็นด้านกายภาพ ศีลธรรม หรือพฤติกรรม"),
    (53,"หลักประกันภัย","ข้อใดเป็นตัวอย่างสภาวะภัยทางกายภาพ?",["สายไฟเก่าชำรุดในอาคาร","เจตนาแจ้งข้อมูลเท็จ","ความประมาทเพราะมีประกัน","การรับช่วงสิทธิ"],"สายไฟเก่าชำรุดในอาคาร","ลักษณะทางกายภาพที่เพิ่มโอกาสเกิดไฟเป็น Physical Hazard"),
    (54,"หลักประกันภัย","ข้อใดเป็นตัวอย่างสภาวะภัยทางศีลธรรม?",["จงใจวางเพลิงเพื่อหวังเงินประกัน","พื้นโรงงานลื่น","ฝนตกหนัก","รถมีอายุมาก"],"จงใจวางเพลิงเพื่อหวังเงินประกัน","Moral Hazard เกี่ยวกับความไม่ซื่อสัตย์หรือเจตนาทุจริต"),
    (55,"หลักประกันภัย","ความเสี่ยงภัยแท้จริง (Pure Risk) มีผลลัพธ์แบบใด?",["เสียหายหรือไม่เสียหาย โดยไม่มีโอกาสกำไรจากเหตุ","ขาดทุนหรือกำไรจากการเก็งกำไร","กำไรแน่นอน","ไม่มีความไม่แน่นอน"],"เสียหายหรือไม่เสียหาย โดยไม่มีโอกาสกำไรจากเหตุ","ความเสี่ยงภัยแท้จริงเป็นชนิดที่เหมาะต่อการประกันภัยโดยทั่วไป"),
    (56,"หลักประกันภัย","การกระจายความเสี่ยงของบริษัทประกันภัยทำได้โดยวิธีใด?",["รับประกันภัยจำนวนมากและใช้การประกันภัยต่อ","รับประกันเพียงรายเดียว","ปฏิเสธสินไหมทั้งหมด","เก็บข้อมูลให้น้อยที่สุด"],"รับประกันภัยจำนวนมากและใช้การประกันภัยต่อ","กฎจำนวนมากและการประกันภัยต่อช่วยลดความผันผวนของความเสียหาย"),
    (57,"หลักประกันภัย","เบี้ยประกันภัยคือข้อใด?",["จำนวนเงินที่ผู้เอาประกันภัยชำระเพื่อแลกกับความคุ้มครอง","ค่าสินไหมที่บริษัทจ่าย","ราคาทรัพย์สินเสมอ","ค่าปรับตามกฎหมาย"],"จำนวนเงินที่ผู้เอาประกันภัยชำระเพื่อแลกกับความคุ้มครอง","เบี้ยเป็นค่าตอบแทนที่ผู้เอาประกันภัยตกลงชำระตามสัญญา"),
    (58,"หลักประกันภัย","ผู้รับประกันภัยหมายถึงใคร?",["บริษัทที่ตกลงรับเสี่ยงภัยตามกรมธรรม์","ผู้ซื้อประกันเท่านั้น","ผู้เสียหายภายนอก","นายหน้าทุกคน"],"บริษัทที่ตกลงรับเสี่ยงภัยตามกรมธรรม์","ผู้รับประกันภัยเป็นคู่สัญญาฝ่ายที่รับเสี่ยงและมีหน้าที่ชดใช้ตามเงื่อนไข"),
    (59,"หลักประกันภัย","ผู้เอาประกันภัยหมายถึงใคร?",["คู่สัญญาฝ่ายที่ตกลงชำระเบี้ยและได้รับความคุ้มครองตามกรมธรรม์","บริษัทสำรวจภัย","พนักงานสอบสวน","ผู้ซ่อมทรัพย์"],"คู่สัญญาฝ่ายที่ตกลงชำระเบี้ยและได้รับความคุ้มครองตามกรมธรรม์","ต้องแยกผู้เอาประกันภัยออกจากผู้รับประโยชน์และผู้รับประกันภัย"),
    (60,"หลักประกันภัย","หลักสาเหตุใกล้ชิดใช้เพื่ออะไร?",["พิจารณาสาเหตุสำคัญที่มีประสิทธิผลต่อความเสียหาย","คำนวณภาษีรถ","กำหนดอายุผู้เอาประกันภัย","เลือกนายหน้า"],"พิจารณาสาเหตุสำคัญที่มีประสิทธิผลต่อความเสียหาย","ใช้วินิจฉัยว่าความเสียหายเกิดจากภัยที่คุ้มครองหรือข้อยกเว้น"),

    (61,"ประกันอัคคีภัย","กรมธรรม์อัคคีภัยมาตรฐานมุ่งคุ้มครองสิ่งใด?",["ความเสียหายต่อทรัพย์สินจากภัยที่ระบุ","ชีวิตผู้เอาประกันภัยทุกกรณี","การขาดทุนจากราคาหุ้น","รถยนต์บนถนนทุกคัน"],"ความเสียหายต่อทรัพย์สินจากภัยที่ระบุ","ต้องดูทรัพย์สินที่เอาประกันภัย ภัยที่คุ้มครอง และข้อยกเว้น"),
    (62,"ประกันอัคคีภัย","ทรัพย์สินต่ำกว่ามูลค่าที่แท้จริงอย่างมีนัยสำคัญ อาจเกิดผลใดเมื่อมีความเสียหายบางส่วน?",["อาจนำหลักเฉลี่ยมาใช้ลดค่าสินไหมตามสัดส่วน","ได้ค่าสินไหมสองเท่า","กรมธรรม์กลายเป็นประกันชีวิต","บริษัทต้องจ่ายเกินทุน"],"อาจนำหลักเฉลี่ยมาใช้ลดค่าสินไหมตามสัดส่วน","การเอาประกันภัยต่ำกว่ามูลค่าทำให้ผู้เอาประกันภัยเสมือนรับเสี่ยงส่วนหนึ่งเอง"),
    (63,"ประกันอัคคีภัย","การเอาประกันภัยเกินมูลค่าทรัพย์สินทำให้ได้รับกำไรจากความเสียหายหรือไม่?",["ไม่ได้ โดยหลักชดใช้ไม่เกินความเสียหายจริงและวงเงิน","ได้เสมอ","ได้เฉพาะกลางคืน","ขึ้นกับราคาทองคำ"],"ไม่ได้ โดยหลักชดใช้ไม่เกินความเสียหายจริงและวงเงิน","หลักการชดใช้ค่าสินไหมป้องกันไม่ให้ผู้เอาประกันภัยได้กำไรจากเหตุ"),
    (64,"ประกันอัคคีภัย","ข้อใดควรระบุให้ชัดในประกันอัคคีภัย?",["สถานที่ตั้งและลักษณะทรัพย์สินที่เอาประกันภัย","สีโปรดของเจ้าของ","ชื่อช่างซ่อมรถ","เลขที่ใบขับขี่ทุกคน"],"สถานที่ตั้งและลักษณะทรัพย์สินที่เอาประกันภัย","สถานที่และประเภททรัพย์มีผลต่อขอบเขตความคุ้มครองและการประเมินภัย"),
    (65,"ประกันอัคคีภัย","สต็อกสินค้าเปลี่ยนแปลงขึ้นลงมาก ผู้เอาประกันภัยควรทำอย่างไร?",["แจ้งข้อมูลและเลือกแบบความคุ้มครองที่เหมาะกับมูลค่าที่ผันผวน","ปกปิดมูลค่าสูงสุด","ใช้ทุนประกันศูนย์บาท","ไม่ต้องทำบัญชีสินค้า"],"แจ้งข้อมูลและเลือกแบบความคุ้มครองที่เหมาะกับมูลค่าที่ผันผวน","ข้อมูลสต็อกที่ถูกต้องลดปัญหาเอาประกันต่ำกว่ามูลค่าและช่วยพิสูจน์ความเสียหาย"),
    (66,"ประกันอัคคีภัย","ค่าเก็บซากหลังเพลิงไหม้จะได้รับชดใช้เสมอหรือไม่?",["ต้องดูว่ามีความคุ้มครองและวงเงินตามกรมธรรม์หรือเอกสารแนบท้ายหรือไม่","ได้ไม่จำกัดเสมอ","ไม่ได้ทุกกรณี","จ่ายโดย พ.ร.บ. รถ"],"ต้องดูว่ามีความคุ้มครองและวงเงินตามกรมธรรม์หรือเอกสารแนบท้ายหรือไม่","ค่าใช้จ่ายประกอบต้องตรวจข้อความกรมธรรม์ ไม่ควรสัญญาเหมารวม"),
    (67,"ประกันอัคคีภัย","เมื่อเกิดไฟไหม้ ผู้เอาประกันภัยมีหน้าที่สำคัญข้อใด?",["พยายามบรรเทาความเสียหายและแจ้งบริษัทโดยเร็ว","ปล่อยให้ไฟลุกเพื่อรอสำรวจ","ทิ้งหลักฐานทั้งหมด","เพิ่มทุนย้อนหลัง"],"พยายามบรรเทาความเสียหายและแจ้งบริษัทโดยเร็ว","ต้องคำนึงถึงความปลอดภัยก่อน พร้อมรักษาทรัพย์และหลักฐานเท่าที่ทำได้"),
    (68,"ประกันอัคคีภัย","การเปลี่ยนอาคารจากที่พักเป็นโรงงานโดยไม่แจ้งบริษัทอาจสำคัญเพราะเหตุใด?",["เป็นการเปลี่ยนแปลงลักษณะความเสี่ยง","ทำให้ที่ดินหาย","เปลี่ยนผู้รับประกันภัยอัตโนมัติ","ไม่มีผลใดเสมอ"],"เป็นการเปลี่ยนแปลงลักษณะความเสี่ยง","การใช้สถานที่มีผลต่อโอกาสและความรุนแรงของภัย จึงควรแจ้งบริษัท"),
    (69,"ประกันอัคคีภัย","ทุนประกันอาคารควรพิจารณาจากอะไรเป็นสำคัญ?",["มูลค่าที่เหมาะสมตามหลักประเมินและเงื่อนไขกรมธรรม์","ยอดหนี้บัตรเครดิต","รายได้รายวันของเจ้าของ","เลขที่บ้าน"],"มูลค่าที่เหมาะสมตามหลักประเมินและเงื่อนไขกรมธรรม์","ควรแยกมูลค่าสิ่งปลูกสร้างออกจากมูลค่าที่ดินซึ่งไม่ถูกไฟทำลาย"),
    (70,"ประกันอัคคีภัย","มูลค่าที่ดินควรรวมในทุนประกันอัคคีภัยอาคารตามปกติหรือไม่?",["โดยทั่วไปไม่รวม เพราะที่ดินไม่ถูกทำลายด้วยไฟแบบตัวอาคาร","ต้องรวมสองเท่า","รวมเฉพาะฤดูฝน","รวมแทนมูลค่าอาคาร"],"โดยทั่วไปไม่รวม เพราะที่ดินไม่ถูกทำลายด้วยไฟแบบตัวอาคาร","ทุนประกันสิ่งปลูกสร้างมักอิงต้นทุนสร้างทดแทนตามหลักเกณฑ์ ไม่ใช่ราคาที่ดินรวม"),

    (71,"ประกันภัยทางทะเลและขนส่ง","ประกันภัยสินค้าระหว่างขนส่งมุ่งคุ้มครองอะไร?",["ความเสียหายต่อสินค้าจากภัยระหว่างการขนส่งตามเงื่อนไข","กำไรจากอัตราแลกเปลี่ยน","ชีวิตลูกเรือทุกกรณี","ค่าซ่อมโรงงานต้นทาง"],"ความเสียหายต่อสินค้าจากภัยระหว่างการขนส่งตามเงื่อนไข","ขอบเขตขึ้นกับเงื่อนไขภัย เส้นทาง ระยะเวลา และข้อยกเว้น"),
    (72,"ประกันภัยทางทะเลและขนส่ง","กรมธรรม์แบบเที่ยว (Voyage Policy) ผูกความคุ้มครองกับอะไร?",["การเดินทางหรือเส้นทางที่กำหนด","ระยะเวลาสิบปีเสมอ","อายุผู้ขนส่ง","จำนวนพนักงานบริษัท"],"การเดินทางหรือเส้นทางที่กำหนด","ต่างจากกรมธรรม์แบบกำหนดเวลาซึ่งเน้นช่วงเวลาคุ้มครอง"),
    (73,"ประกันภัยทางทะเลและขนส่ง","กรมธรรม์แบบกำหนดเวลา (Time Policy) ผูกความคุ้มครองกับอะไร?",["ช่วงเวลาที่ระบุ","เที่ยวขนส่งเดียวเท่านั้นเสมอ","ราคาสินค้าหน้าร้าน","จำนวนรถของผู้ซื้อ"],"ช่วงเวลาที่ระบุ","ต้องอ่านวันและเวลาเริ่มสิ้นสุดให้ชัดเจน"),
    (74,"ประกันภัยทางทะเลและขนส่ง","ความเสียหายร่วม (General Average) มีแนวคิดสำคัญอย่างไร?",["ผู้มีส่วนได้เสียร่วมกันเฉลี่ยรับภาระจากการเสียสละเพื่อความปลอดภัยส่วนรวม","เจ้าของเรือรับผิดคนเดียวทุกกรณี","บริษัทประกันจ่ายโดยไม่มีหลักฐาน","ผู้ซื้อสินค้าจ่ายค่าขนส่งซ้ำ"],"ผู้มีส่วนได้เสียร่วมกันเฉลี่ยรับภาระจากการเสียสละเพื่อความปลอดภัยส่วนรวม","เป็นหลักเฉพาะสำคัญของการเดินเรือและการค้าทางทะเล"),
    (75,"ประกันภัยทางทะเลและขนส่ง","หีบห่อไม่เหมาะสมจนสินค้าเสียหาย อาจมีผลอย่างไร?",["อาจเข้าข้อยกเว้นหรือกระทบสินไหมตามเงื่อนไข","คุ้มครองเต็มจำนวนเสมอ","ทำให้ทุนประกันเพิ่ม","เปลี่ยนเป็นประกันอัคคีภัย"],"อาจเข้าข้อยกเว้นหรือกระทบสินไหมตามเงื่อนไข","การบรรจุหีบห่อเป็นข้อเท็จจริงสำคัญในการป้องกันความเสียหายระหว่างขนส่ง"),
    (76,"ประกันภัยทางทะเลและขนส่ง","ผู้เอาประกันภัยสินค้าควรเก็บเอกสารใดไว้เรียกร้องสินไหม?",["ใบกำกับสินค้า เอกสารขนส่ง หลักฐานความเสียหาย และหนังสือเรียกร้อง","เฉพาะนามบัตร","เฉพาะภาพสินค้าเดิม","ไม่ต้องใช้เอกสาร"],"ใบกำกับสินค้า เอกสารขนส่ง หลักฐานความเสียหาย และหนังสือเรียกร้อง","เอกสารใช้ยืนยันส่วนได้เสีย มูลค่า เส้นทาง และเหตุความเสียหาย"),
    (77,"ประกันภัยทางทะเลและขนส่ง","คำว่า Warehouse to Warehouse สื่อถึงอะไร?",["ช่วงความคุ้มครองการขนส่งจากคลังต้นทางถึงคลังปลายทางตามเงื่อนไข","คุ้มครองตัวอาคารคลังตลอดไป","คุ้มครองเฉพาะเรือจอด","รับประกันคุณภาพสินค้า"],"ช่วงความคุ้มครองการขนส่งจากคลังต้นทางถึงคลังปลายทางตามเงื่อนไข","ไม่ได้หมายถึงไม่จำกัดเวลา ต้องดูจุดเริ่ม สิ้นสุด และเงื่อนไขการขนส่ง"),
    (78,"ประกันภัยทางทะเลและขนส่ง","การล่าช้าเพียงอย่างเดียวในการขนส่ง โดยทั่วไปควรสรุปอย่างไร?",["มักเป็นข้อยกเว้น เว้นแต่มีข้อตกลงเฉพาะ","คุ้มครองทุกกรมธรรม์","จ่ายเท่าทุนประกันเสมอ","เป็นความเสียหายร่วมทุกครั้ง"],"มักเป็นข้อยกเว้น เว้นแต่มีข้อตกลงเฉพาะ","ต้องแยกความเสียหายจากภัยที่คุ้มครองออกจากผลของความล่าช้า"),
    (79,"ประกันภัยทางทะเลและขนส่ง","การประกันภัยตัวเรือแตกต่างจากประกันภัยสินค้าอย่างไร?",["ตัวเรือคุ้มครองส่วนได้เสียในเรือ ส่วนสินค้าคุ้มครองสินค้า","ไม่มีความแตกต่าง","ตัวเรือคุ้มครองบ้าน","สินค้าคุ้มครองชีวิตผู้ซื้อ"],"ตัวเรือคุ้มครองส่วนได้เสียในเรือ ส่วนสินค้าคุ้มครองสินค้า","วัตถุที่เอาประกันและผู้มีส่วนได้เสียต่างกัน"),
    (80,"ประกันภัยทางทะเลและขนส่ง","การแจ้งชนิดสินค้าไม่ตรงจริงมีความสำคัญเพราะเหตุใด?",["ชนิดสินค้ามีผลต่อการประเมินความเสี่ยงและเงื่อนไข","ไม่มีผลต่อการรับประกัน","ใช้แทนเลขกรมธรรม์ได้","ทำให้การขนส่งเร็วขึ้น"],"ชนิดสินค้ามีผลต่อการประเมินความเสี่ยงและเงื่อนไข","สินค้าเปราะบาง เน่าเสียง่าย หรืออันตรายมีความเสี่ยงแตกต่างกัน"),

    (81,"ประกันภัยเบ็ดเตล็ด","ประกันอุบัติเหตุส่วนบุคคลมุ่งคุ้มครองเหตุใด?",["การบาดเจ็บ สูญเสียอวัยวะ ทุพพลภาพ หรือเสียชีวิตจากอุบัติเหตุตามเงื่อนไข","การเจ็บป่วยทุกโรคเสมอ","รถสูญหาย","บ้านไฟไหม้"],"การบาดเจ็บ สูญเสียอวัยวะ ทุพพลภาพ หรือเสียชีวิตจากอุบัติเหตุตามเงื่อนไข","ต้องดูคำนิยามอุบัติเหตุ ตารางผลประโยชน์ และข้อยกเว้น"),
    (82,"ประกันภัยเบ็ดเตล็ด","ประกันสุขภาพแตกต่างจาก PA อย่างไรโดยหลัก?",["สุขภาพอาจคุ้มครองการเจ็บป่วยตามเงื่อนไข ส่วน PA เน้นอุบัติเหตุ","ไม่มีความแตกต่าง","PA คุ้มครองทรัพย์สิน","สุขภาพคุ้มครองรถ"],"สุขภาพอาจคุ้มครองการเจ็บป่วยตามเงื่อนไข ส่วน PA เน้นอุบัติเหตุ","ขอบเขตจริงต้องยึดกรมธรรม์และเอกสารแนบท้าย"),
    (83,"ประกันภัยเบ็ดเตล็ด","ประกันความรับผิดต่อบุคคลภายนอกจะชดใช้เมื่อใดโดยหลัก?",["เมื่อผู้เอาประกันภัยมีความรับผิดตามกฎหมายและอยู่ในขอบเขตกรมธรรม์","เมื่ออยากช่วยคู่กรณีแม้ไม่รับผิด","เมื่อทรัพย์ตนเองเสียหายเสมอ","เมื่อเบี้ยลดลง"],"เมื่อผู้เอาประกันภัยมีความรับผิดตามกฎหมายและอยู่ในขอบเขตกรมธรรม์","ต้องมีทั้งความรับผิดตามกฎหมายและเหตุอยู่ในความคุ้มครอง"),
    (84,"ประกันภัยเบ็ดเตล็ด","ประกันโจรกรรมมักต้องพิจารณาประเด็นใด?",["ลักษณะการเข้าออก ร่องรอย และคำนิยามภัยตามกรมธรรม์","สีของท้องฟ้า","อายุผู้ขายประกัน","ระยะทางถึงทะเลเท่านั้น"],"ลักษณะการเข้าออก ร่องรอย และคำนิยามภัยตามกรมธรรม์","คำว่าโจรกรรม ลักทรัพย์ หรือชิงทรัพย์อาจมีขอบเขตเฉพาะในกรมธรรม์"),
    (85,"ประกันภัยเบ็ดเตล็ด","ประกันความเสี่ยงภัยทุกชนิด (All Risks) หมายถึงคุ้มครองทุกสิ่งโดยไม่มีข้อยกเว้นหรือไม่?",["ไม่ใช่ ยังคงมีข้อยกเว้น เงื่อนไข และวงเงิน","ใช่ ไม่มีข้อยกเว้นเลย","คุ้มครองเฉพาะไฟไหม้","เป็นประกันชีวิต"],"ไม่ใช่ ยังคงมีข้อยกเว้น เงื่อนไข และวงเงิน","คำว่า All Risks ไม่ควรถูกอธิบายแก่ลูกค้าว่าเคลมได้ทุกกรณี"),
    (86,"ประกันภัยเบ็ดเตล็ด","ประกันเงินสดอาจคุ้มครองความเสี่ยงใด?",["การสูญเสียเงินในสถานที่หรือระหว่างขนส่งตามเงื่อนไข","ราคาหุ้นตก","ลูกหนี้ไม่ชำระทุกกรณี","ค่าเสื่อมรถ"],"การสูญเสียเงินในสถานที่หรือระหว่างขนส่งตามเงื่อนไข","ต้องดูนิยามเงิน วิธีเก็บรักษา เส้นทาง และข้อกำหนดความปลอดภัย"),
    (87,"ประกันภัยเบ็ดเตล็ด","ประกันความซื่อสัตย์ของลูกจ้างเกี่ยวข้องกับภัยใด?",["การทุจริตของลูกจ้างที่ก่อความเสียหายแก่นายจ้างตามเงื่อนไข","อุบัติเหตุรถของลูกค้า","ไฟไหม้จากฟ้าผ่า","สุขภาพของผู้ซื้อ"],"การทุจริตของลูกจ้างที่ก่อความเสียหายแก่นายจ้างตามเงื่อนไข","ต้องพิสูจน์การกระทำและความเสียหายภายในขอบเขตและระยะเวลาที่กำหนด"),
    (88,"ประกันภัยเบ็ดเตล็ด","ประกันเครื่องจักรเสียหายมุ่งคุ้มครองสิ่งใด?",["ความเสียหายทางกายภาพของเครื่องจักรจากเหตุที่คุ้มครอง","ยอดขายลดลงทุกกรณี","ชีวิตผู้ควบคุม","หนี้สินบริษัท"],"ความเสียหายทางกายภาพของเครื่องจักรจากเหตุที่คุ้มครอง","การสึกหรอตามปกติมักไม่ใช่ภัยที่มุ่งคุ้มครอง"),
    (89,"ประกันภัยเบ็ดเตล็ด","ประกันภัยธุรกิจหยุดชะงักมักต้องอาศัยอะไรเป็นฐานสำคัญ?",["ความเสียหายทางกายภาพจากภัยที่คุ้มครองตามกรมธรรม์หลักและเงื่อนไข","การลาออกของพนักงานหนึ่งคนเสมอ","ยอดขายไม่ถึงเป้า","การเปลี่ยนโลโก้"],"ความเสียหายทางกายภาพจากภัยที่คุ้มครองตามกรมธรรม์หลักและเงื่อนไข","คุ้มครองผลกระทบทางธุรกิจตามระยะเวลาชดใช้และรายการที่กำหนด"),
    (90,"ประกันภัยเบ็ดเตล็ด","ประกันภัยก่อสร้างมักคุ้มครองในช่วงใด?",["ระหว่างดำเนินงานก่อสร้างตามระยะเวลาและเงื่อนไข","หลังอาคารรื้อถอนถาวรเท่านั้น","เฉพาะก่อนเริ่มงาน","ตลอดไปโดยไม่สิ้นสุด"],"ระหว่างดำเนินงานก่อสร้างตามระยะเวลาและเงื่อนไข","อาจมีช่วงบำรุงรักษาตามที่ระบุ แต่ไม่ควรเหมารวมทุกกรมธรรม์"),

    (91,"กฎหมายประกันภัย","สัญญาประกันภัยเป็นสัญญาที่คู่สัญญาต้องปฏิบัติต่อกันอย่างไร?",["สุจริตและเปิดเผยข้อเท็จจริงสำคัญ","ปกปิดข้อมูลได้เต็มที่","ตกลงด้วยวาจาแทนเอกสารทุกกรณี","เปลี่ยนเงื่อนไขฝ่ายเดียวได้เสมอ"],"สุจริตและเปิดเผยข้อเท็จจริงสำคัญ","ข้อเท็จจริงที่มีผลต่อการตัดสินใจรับเสี่ยงต้องได้รับการเปิดเผยอย่างถูกต้อง"),
    (92,"กฎหมายประกันภัย","การแถลงข้อความเท็จในข้อสาระสำคัญอาจมีผลอย่างไรต่อสัญญา?",["อาจทำให้สัญญาเป็นโมฆียะตามหลักกฎหมาย","ทำให้ทุนเพิ่มอัตโนมัติ","ไม่มีผลเสมอ","ทำให้บริษัทต้องจ่ายสองเท่า"],"อาจทำให้สัญญาเป็นโมฆียะตามหลักกฎหมาย","ต้องพิจารณาว่าเป็นข้อที่ถ้ารู้แล้วบริษัทอาจเรียกเบี้ยสูงขึ้นหรือไม่รับประกัน"),
    (93,"กฎหมายประกันภัย","โมฆียะแตกต่างจากโมฆะอย่างไร?",["โมฆียะยังมีผลจนกว่าจะถูกบอกล้าง ส่วนโมฆะเสียเปล่ามาแต่ต้น","เหมือนกันทุกประการ","โมฆียะไม่มีวันบอกล้างได้","โมฆะมีผลสมบูรณ์เสมอ"],"โมฆียะยังมีผลจนกว่าจะถูกบอกล้าง ส่วนโมฆะเสียเปล่ามาแต่ต้น","เป็นแนวคิดพื้นฐานในกฎหมายสัญญาที่ข้อสอบมักถามแยกคำ"),
    (94,"กฎหมายประกันภัย","กรมธรรม์ประกันภัยมีความสำคัญอย่างไร?",["เป็นหลักฐานและแสดงรายละเอียดสิทธิหน้าที่ตามสัญญา","ใช้แทนทะเบียนบ้าน","เป็นใบเสร็จค่าซ่อมเท่านั้น","ไม่มีผลทางกฎหมาย"],"เป็นหลักฐานและแสดงรายละเอียดสิทธิหน้าที่ตามสัญญา","ผู้ขายควรส่งมอบและชี้แจงสาระสำคัญให้ผู้เอาประกันภัย"),
    (95,"กฎหมายประกันภัย","ผู้รับประโยชน์หมายถึงใคร?",["บุคคลที่กำหนดให้มีสิทธิรับประโยชน์ตามสัญญา","ผู้รับประกันภัยเสมอ","นายหน้าผู้ขายเสมอ","ผู้สำรวจภัย"],"บุคคลที่กำหนดให้มีสิทธิรับประโยชน์ตามสัญญา","ผู้รับประโยชน์อาจเป็นหรือไม่เป็นบุคคลเดียวกับผู้เอาประกันภัย"),
    (96,"กฎหมายประกันภัย","บริษัทประกันภัยจะประกอบธุรกิจได้ต้องอยู่ภายใต้สิ่งใด?",["ใบอนุญาตและการกำกับตามกฎหมายประกันวินาศภัย","เพียงจดทะเบียนร้านค้าทั่วไป","การอนุญาตจากนายหน้าคนใดก็ได้","ไม่ต้องมีการกำกับ"],"ใบอนุญาตและการกำกับตามกฎหมายประกันวินาศภัย","ธุรกิจรับประกันภัยเกี่ยวข้องกับประโยชน์สาธารณะจึงอยู่ภายใต้การกำกับ"),
    (97,"กฎหมายประกันภัย","การใช้คำว่า 'บริษัทประกันภัย' โดยผู้ไม่มีสิทธิอาจมีปัญหาเพราะเหตุใด?",["อาจทำให้ประชาชนเข้าใจผิดและขัดกฎหมายกำกับธุรกิจ","เป็นคำทั่วไปที่ใช้ได้เสมอ","ทำให้เบี้ยถูกลง","ไม่มีผู้เสียหายได้"],"อาจทำให้ประชาชนเข้าใจผิดและขัดกฎหมายกำกับธุรกิจ","การแสดงตนและชื่อธุรกิจต้องไม่หลอกให้เข้าใจว่าได้รับอนุญาต"),
    (98,"กฎหมายประกันภัย","เงินกองทุนของบริษัทประกันภัยมีความสำคัญอย่างไร?",["เป็นฐานความมั่นคงเพื่อรองรับภาระผูกพันต่อผู้เอาประกันภัย","ใช้จ่ายโฆษณาเท่านั้น","เป็นค่านายหน้าทั้งหมด","ไม่เกี่ยวกับผู้เอาประกันภัย"],"เป็นฐานความมั่นคงเพื่อรองรับภาระผูกพันต่อผู้เอาประกันภัย","กฎหมายกำกับฐานะการเงินเพื่อคุ้มครองประชาชนและเสถียรภาพของระบบ"),
    (99,"กฎหมายประกันภัย","สำรองประกันภัยมีไว้เพื่ออะไร?",["รองรับภาระค่าสินไหมและหนี้ตามกรมธรรม์","จ่ายเงินเดือนนายหน้าเท่านั้น","ซื้อรถบริษัทเท่านั้น","ใช้แทนเบี้ยประกัน"],"รองรับภาระค่าสินไหมและหนี้ตามกรมธรรม์","บริษัทต้องจัดสรรตามหลักเกณฑ์เพื่อให้มีเงินรองรับภาระในอนาคต"),
    (100,"กฎหมายประกันภัย","เมื่อมีข้อพิพาทด้านประกันภัย ผู้เอาประกันภัยสามารถติดต่อหน่วยงานกำกับใด?",["สำนักงาน คปภ.","กรมอุตุนิยมวิทยา","กรมศิลปากร","ธนาคารแห่งประเทศไทยเท่านั้น"],"สำนักงาน คปภ.","คปภ. มีช่องทางรับเรื่องร้องเรียนและส่งเสริมการระงับข้อพิพาทด้านประกันภัย"),

    (101,"จรรยาบรรณนายหน้า","นายหน้าประกันวินาศภัยทำหน้าที่สำคัญอย่างไร?",["ชี้ช่องหรือจัดการให้บุคคลทำสัญญาประกันภัยกับบริษัทโดยได้รับบำเหน็จ","รับประกันภัยไว้เองโดยไม่ต้องมีบริษัท","ตัดสินคดีแทนศาล","ออกใบขับขี่"],"ชี้ช่องหรือจัดการให้บุคคลทำสัญญาประกันภัยกับบริษัทโดยได้รับบำเหน็จ","นายหน้าเป็นคนกลาง ไม่ใช่บริษัทผู้รับเสี่ยงภัย"),
    (102,"จรรยาบรรณนายหน้า","นายหน้าควรแสดงใบอนุญาตหรือข้อมูลใบอนุญาตเมื่อใด?",["เมื่อปฏิบัติงานและเมื่อลูกค้าขอตรวจสอบตามหลักเกณฑ์","ไม่ต้องแสดงเลย","หลังกรมธรรม์หมดอายุเท่านั้น","เฉพาะวันสอบ"],"เมื่อปฏิบัติงานและเมื่อลูกค้าขอตรวจสอบตามหลักเกณฑ์","ลูกค้าควรตรวจสอบตัวตนและสถานะใบอนุญาตของผู้เสนอขายได้"),
    (103,"จรรยาบรรณนายหน้า","การโฆษณาว่า 'เคลมได้ทุกกรณี 100%' เหมาะสมหรือไม่?",["ไม่เหมาะสม เพราะทำให้เข้าใจผิดและไม่กล่าวถึงเงื่อนไขหรือข้อยกเว้น","เหมาะสมเสมอ","เหมาะเฉพาะโพสต์ส่วนตัว","เป็นคำที่กฎหมายบังคับให้ใช้"],"ไม่เหมาะสม เพราะทำให้เข้าใจผิดและไม่กล่าวถึงเงื่อนไขหรือข้อยกเว้น","การสื่อสารต้องถูกต้อง ชัดเจน และไม่เกินจริง"),
    (104,"จรรยาบรรณนายหน้า","หากไม่แน่ใจคำตอบเกี่ยวกับความคุ้มครอง นายหน้าควรทำอย่างไร?",["ตรวจกรมธรรม์และสอบถามบริษัทก่อนให้ข้อมูลยืนยัน","เดาคำตอบที่ลูกค้าน่าจะชอบ","รับรองว่าคุ้มครองไว้ก่อน","หลีกเลี่ยงการบันทึกข้อมูล"],"ตรวจกรมธรรม์และสอบถามบริษัทก่อนให้ข้อมูลยืนยัน","ความถูกต้องสำคัญกว่าความเร็วในการตอบ และควรเก็บหลักฐานการชี้แจง"),
    (105,"จรรยาบรรณนายหน้า","การเก็บเบี้ยประกันจากลูกค้าควรทำอย่างไร?",["ออกหลักฐาน รับและนำส่งตามอำนาจกับระยะเวลาที่กำหนด","รับเข้าบัญชีส่วนตัวและใช้ก่อนได้","ไม่ต้องออกหลักฐาน","เปลี่ยนจำนวนเงินเองได้"],"ออกหลักฐาน รับและนำส่งตามอำนาจกับระยะเวลาที่กำหนด","เงินของลูกค้าต้องถูกจัดการโปร่งใส ตรวจสอบได้ และไม่ปะปนโดยมิชอบ"),
    (106,"จรรยาบรรณนายหน้า","นายหน้าควรแนะนำให้ลูกค้ากรอกข้อมูลอย่างไร?",["ตรงตามความจริงและครบถ้วน","ลดอายุรถเพื่อให้เบี้ยถูก","ปิดบังการใช้รถรับจ้าง","ให้เว้นทุกช่องสำคัญ"],"ตรงตามความจริงและครบถ้วน","ข้อมูลเท็จอาจกระทบการรับประกัน สัญญา และการเรียกร้องสินไหม"),
    (107,"จรรยาบรรณนายหน้า","เมื่อลูกค้าไม่เข้าใจข้อยกเว้น นายหน้าควรทำอย่างไร?",["อธิบายด้วยภาษาที่เข้าใจง่ายและเปิดโอกาสให้ถาม","บอกให้อ่านเองทั้งหมด","ซ่อนหน้าข้อยกเว้น","เร่งให้ชำระก่อน"],"อธิบายด้วยภาษาที่เข้าใจง่ายและเปิดโอกาสให้ถาม","การเสนอขายที่เป็นธรรมต้องช่วยให้ลูกค้าตัดสินใจจากข้อมูลเพียงพอ"),
    (108,"จรรยาบรรณนายหน้า","การเลือกผลิตภัณฑ์ให้ลูกค้าควรยึดอะไร?",["ความต้องการ ความเสี่ยง และความสามารถในการชำระเบี้ยของลูกค้า","ค่าตอบแทนของผู้ขายเพียงอย่างเดียว","ยอดขายของทีมเท่านั้น","สีกรมธรรม์"],"ความต้องการ ความเสี่ยง และความสามารถในการชำระเบี้ยของลูกค้า","แนวทางเสนอขายที่เหมาะสมช่วยลดการขายผิดความต้องการ"),
    (109,"จรรยาบรรณนายหน้า","ข้อมูลสุขภาพหรือเลขบัตรประชาชนของลูกค้าควรถูกส่งในกลุ่มสาธารณะหรือไม่?",["ไม่ควร ต้องจำกัดการเข้าถึงและใช้ช่องทางที่ปลอดภัย","ควรเพื่อให้ทำงานเร็ว","ส่งได้ถ้าปิดชื่อเล่น","ส่งได้เสมอหลังเลิกงาน"],"ไม่ควร ต้องจำกัดการเข้าถึงและใช้ช่องทางที่ปลอดภัย","ข้อมูลส่วนบุคคลและข้อมูลอ่อนไหวต้องได้รับการดูแลตามความจำเป็นและฐานกฎหมาย"),
    (110,"จรรยาบรรณนายหน้า","เมื่อลูกค้าร้องเรียน นายหน้าควรทำอย่างไร?",["รับฟัง บันทึกข้อเท็จจริง แจ้งช่องทาง และติดตามอย่างเป็นธรรม","ลบข้อความลูกค้า","โต้เถียงในสื่อสาธารณะ","รับรองผลสินไหมทันทีโดยไม่ตรวจสอบ"],"รับฟัง บันทึกข้อเท็จจริง แจ้งช่องทาง และติดตามอย่างเป็นธรรม","การจัดการข้อร้องเรียนที่ตรวจสอบได้เป็นส่วนหนึ่งของบริการหลังการขาย"),

    (111,"ประกันภาคสมัครใจ","ค่าขาดประโยชน์จากการใช้รถเป็นความเสียหายประเภทใด?",["ความเสียหายจากการไม่ได้ใช้รถระหว่างซ่อมซึ่งต้องพิสูจน์สิทธิและจำนวน","ค่าซ่อมเครื่องยนต์ตามอายุ","ค่าเบี้ยประกัน","ค่าปรับทะเบียน"],"ความเสียหายจากการไม่ได้ใช้รถระหว่างซ่อมซึ่งต้องพิสูจน์สิทธิและจำนวน","ผู้เสียหายควรเก็บหลักฐานระยะเวลาซ่อมและความจำเป็นในการใช้รถ"),
    (112,"ประกันภาคสมัครใจ","การซ่อมห้างกับซ่อมอู่ควรพิจารณาจากอะไร?",["เงื่อนไขที่ระบุในกรมธรรม์และเครือข่ายบริการ","ความต้องการฝ่ายเดียวโดยไม่ดูกรมธรรม์","อายุผู้ขับขี่เท่านั้น","สีรถ"],"เงื่อนไขที่ระบุในกรมธรรม์และเครือข่ายบริการ","ผู้ขายควรอธิบายประเภทการซ่อมก่อนทำประกันเพื่อลดความเข้าใจคลาดเคลื่อน"),
    (113,"ประกันภาคสมัครใจ","น้ำท่วมรถเอาประกันภัยอยู่ในความคุ้มครองใดโดยทั่วไป?",["ต้องดูประเภทกรมธรรม์และความคุ้มครองภัยธรรมชาติที่ระบุ","พ.ร.บ. รถยนต์เสมอ","ประกันตัวผู้ขับขี่","ประเภท 3 ทุกฉบับ"],"ต้องดูประเภทกรมธรรม์และความคุ้มครองภัยธรรมชาติที่ระบุ","ประเภท 1 มักครอบคลุมตามเงื่อนไข ส่วนแบบคุ้มครองเฉพาะภัยต้องตรวจรายละเอียด"),
    (114,"ประกันภาคสมัครใจ","รถสูญหายเพราะผู้เอาประกันภัยมอบรถให้บุคคลแล้วถูกยักยอก ควรสรุปอย่างไร?",["ต้องตรวจข้อเท็จจริงและคำนิยามการสูญหายหรือข้อยกเว้น ไม่ควรรับรองทันที","เป็นโจรกรรมที่จ่ายเสมอ","พ.ร.บ. จ่ายค่ารถ","บริษัทต้องซื้อรถใหม่ทันที"],"ต้องตรวจข้อเท็จจริงและคำนิยามการสูญหายหรือข้อยกเว้น ไม่ควรรับรองทันที","ลักทรัพย์กับยักยอกมีองค์ประกอบต่างกันและอาจมีผลต่อความคุ้มครอง"),
    (115,"ประกันภาคสมัครใจ","ทุนประกันรถยนต์ควรสัมพันธ์กับอะไร?",["มูลค่ารถและหลักเกณฑ์รับประกันของบริษัท","ยอดเงินเดือนผู้ขับ","จำนวนผู้ติดตามในโซเชียล","ราคาน้ำมันวันซื้อ"],"มูลค่ารถและหลักเกณฑ์รับประกันของบริษัท","ทุนที่เหมาะสมช่วยลดปัญหาความคาดหวังเมื่อรถเสียหายสิ้นเชิงหรือสูญหาย"),
    (116,"ประกันภาคสมัครใจ","ความเสียหายสิ้นเชิงของรถหมายความว่าบริษัทต้องซ่อมเสมอหรือไม่?",["ไม่เสมอ ต้องพิจารณามูลค่าความเสียหายและเงื่อนไขการชดใช้","ต้องซ่อมทุกครั้ง","ผู้เอาประกันภัยกำหนดราคาเอง","พ.ร.บ. เป็นผู้ตัดสิน"],"ไม่เสมอ ต้องพิจารณามูลค่าความเสียหายและเงื่อนไขการชดใช้","บางกรณีอาจชดใช้เป็นเงินตามหลักเกณฑ์และมีการโอนซาก"),
    (117,"ประกันภาคสมัครใจ","อุปกรณ์ตกแต่งรถที่เพิ่มภายหลังควรทำอย่างไร?",["แจ้งบริษัทและระบุรายการหรือทุนเพิ่มเติมตามหลักเกณฑ์","ไม่ต้องแจ้งเพราะคุ้มครองไม่จำกัด","ใช้ใบขับขี่แทน","แจ้งหลังเกิดเหตุเท่านั้น"],"แจ้งบริษัทและระบุรายการหรือทุนเพิ่มเติมตามหลักเกณฑ์","อุปกรณ์ที่ไม่ได้เป็นมาตรฐานอาจต้องแจ้งเพื่อให้ขอบเขตและมูลค่าชัดเจน"),
    (118,"ประกันภาคสมัครใจ","กรณีชนแล้วไม่มีคู่กรณี ประกันประเภท 1 ควรพิจารณาอย่างไร?",["อาจคุ้มครองความเสียหายรถตามเงื่อนไขและอาจมีค่าเสียหายส่วนแรก","ไม่คุ้มครองแน่นอนทุกกรณี","ใช้ 3+ แทนโดยอัตโนมัติ","พ.ร.บ. จ่ายค่าซ่อม"],"อาจคุ้มครองความเสียหายรถตามเงื่อนไขและอาจมีค่าเสียหายส่วนแรก","ต้องแจ้งข้อเท็จจริงตรงไปตรงมาและตรวจเงื่อนไขค่าเสียหายส่วนแรก"),
    (119,"ประกันภาคสมัครใจ","การเรียกร้องสินไหมซ้ำซ้อนจากหลายบริษัทจนเกินความเสียหายจริงทำได้หรือไม่?",["ไม่ได้ ขัดหลักชดใช้ค่าสินไหมและอาจเป็นการทุจริต","ได้เสมอหากจ่ายหลายเบี้ย","ได้เฉพาะรถใหม่","ได้เมื่อไม่มีตำรวจ"],"ไม่ได้ ขัดหลักชดใช้ค่าสินไหมและอาจเป็นการทุจริต","การมีหลายกรมธรรม์ไม่ทำให้มีสิทธิได้กำไรจากความเสียหายเดียวกัน"),
    (120,"ประกันภาคสมัครใจ","ก่อนส่งมอบกรมธรรม์ใหั้ลูกค้า นายหน้าควรตรวจอะไร?",["ชื่อผู้เอาประกัน รถ การใช้รถ วันคุ้มครอง ทุน วงเงิน และเงื่อนไขสำคัญ","ตรวจเฉพาะสีเอกสาร","ตรวจเฉพาะค่าคอมมิชชั่น","ไม่ต้องตรวจเพราะแก้ย้อนหลังได้เสมอ"],"ชื่อผู้เอาประกัน รถ การใช้รถ วันคุ้มครอง ทุน วงเงิน และเงื่อนไขสำคัญ","การตรวจความถูกต้องก่อนส่งมอบป้องกันช่องว่างความคุ้มครองและข้อพิพาท"),
]
